// menu.service.ts
import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';
import { BaseService } from '../Base/base.service';
import { Menu } from '../../models';

@Injectable({ providedIn: 'root' })
export class MenuService extends BaseService<Menu> {

  protected override getTableName(): string { return 'menus'; }

  // ── Observable streams ──

  getDefaultActiveMenu$(): Observable<Menu | null> {
    return this.data$.pipe(
      map(menus => menus.find(m => m.is_default && m.is_active) ?? null)
    );
  }

  getActiveMenus$(): Observable<Menu[]> {
    return this.data$.pipe(map(menus => menus.filter(m => m.is_active)));
  }

  getGlobalMenus$(): Observable<Menu[]> {
    return this.data$.pipe(map(menus => menus.filter(m => m.is_active && m.type === 'global')));
  }

  getDedicatedMenus$(): Observable<Menu[]> {
    return this.data$.pipe(map(menus => menus.filter(m => m.is_active && m.type === 'dedicated')));
  }

  // ── patchMenu rimosso: usa direttamente this.update(id, updates) ──
  // BaseService.update() gestisce updated_at, restaurant_id check e refresh automatico.
}