// menu-management.service.ts
import { Injectable, inject } from '@angular/core';
import { Observable } from 'rxjs';
import { MenuService } from './menu.service';
import { MenuDishService } from './menu-dish.service';
import { Menu, MenuDish } from '../../models';

@Injectable({ providedIn: 'root' })
export class MenuManagementService {
  private menuService = inject(MenuService);
  private menuDishService = inject(MenuDishService);

  // ========== DELEGATE A MENU SERVICE ==========
  get menus$(): Observable<Menu[]> {
    return this.menuService.data$;
  }
  get menusLoading$(): Observable<boolean> {
    return this.menuService.loading$;
  }
  get menusError$(): Observable<string | null> {
    return this.menuService.error$;
  }

  async loadMenus(): Promise<void> {
    return this.menuService.loadData();
  }

  async createMenu(
    name: string,
    description?: string,
    isDefault = false,
    type: 'global' | 'dedicated' = 'global'
  ): Promise<Menu | null> {
    const menuData: Partial<Menu> = {
      name,
      description,
      is_default: isDefault,
      is_active: true,
      display_order: 0,
      type,
      is_favorite: false,
    };
    const result = await this.menuService.create(menuData);
    if (result && isDefault) {
      await this.setAsDefault(result.id);
    }
    return result;
  }

  async createDedicatedMenu(name: string, description?: string): Promise<Menu | null> {
    return this.createMenu(name, description, false, 'dedicated');
  }

  async setAsDefault(menuId: string): Promise<boolean> {
    const currentMenus = this.menuService.data;
    const defaultMenus = currentMenus.filter(m => m.is_default);
    const updates = defaultMenus
      .filter(m => m.id !== menuId)
      .map(m => this.menuService.update(m.id, { is_default: false }));
    await Promise.all(updates);

    const success = await this.menuService.update(menuId, {
      is_default: true,
      is_active: true,
      type: 'global',
    });
    if (success) await this.loadMenus();
    return success;
  }

  async toggleMenuActive(menuId: string): Promise<boolean> {
    const menu = this.menuService.data.find(m => m.id === menuId);
    if (!menu || menu.is_default) return false;
    const success = await this.menuService.update(menuId, { is_active: !menu.is_active });
    if (success) await this.loadMenus();
    return success;
  }

  async updateMenu(id: string, updates: Partial<Menu>): Promise<boolean> {
    const success = await this.menuService.update(id, updates);
    if (success) await this.loadMenus();
    return success;
  }

  async deleteMenu(id: string): Promise<boolean> {
    const menu = this.menuService.data.find(m => m.id === id);
    if (menu?.is_default) return false;
    return this.menuService.delete(id);
  }

  // Metodi osservabili specifici (delegati al MenuService)
  getDefaultActiveMenu$(): Observable<Menu | null> {
    return this.menuService.getDefaultActiveMenu$();
  }

  getActiveMenus$(): Observable<Menu[]> {
    return this.menuService.getActiveMenus$();
  }

  getGlobalMenus$(): Observable<Menu[]> {
    return this.menuService.getGlobalMenus$();
  }

  getDedicatedMenus$(): Observable<Menu[]> {
    return this.menuService.getDedicatedMenus$();
  }

  // ========== DELEGATE A MENU DISH SERVICE ==========
  get menuDishes$(): Observable<MenuDish[]> {
    return this.menuDishService.data$;
  }
  get menuDishesLoading$(): Observable<boolean> {
    return this.menuDishService.loading$;
  }
  get menuDishesError$(): Observable<string | null> {
    return this.menuDishService.error$;
  }

  async loadMenuDishes(menuId?: string): Promise<void> {
    return menuId
      ? this.menuDishService.loadData({ menu_id: menuId })
      : this.menuDishService.loadData();
  }

  getDishesByMenu$(menuId: string): Observable<MenuDish[]> {
    return this.menuDishService.getDishesByMenu$(menuId);
  }

  getDishesByMenuOrdered$(menuId: string): Observable<MenuDish[]> {
    return this.menuDishService.getDishesByMenuOrdered$(menuId);
  }

  async addDishToMenu(
    menuId: string,
    dishId: string,
    categoryId?: string | null,
    displayOrder = 0
  ): Promise<MenuDish | null> {
    return this.menuDishService.addDishToMenu(menuId, dishId, categoryId, displayOrder);
  }

  async removeDishFromMenu(menuDishId: string): Promise<boolean> {
    return this.menuDishService.removeDishFromMenu(menuDishId);
  }

  async updateDishOrder(menuDishId: string, displayOrder: number): Promise<boolean> {
    return this.menuDishService.updateDishOrder(menuDishId, displayOrder);
  }

  async getDishesWithDetailsByMenu(menuId: string): Promise<any[]> {
    return this.menuDishService.getDishesWithDetailsByMenu(menuId);
  }

  async removeAllDishesFromMenu(menuId: string): Promise<boolean> {
    return this.menuDishService.removeAllDishesFromMenu(menuId);
  }

  async moveDishInMenu(menuId: string, dishId: string, direction: 'up' | 'down'): Promise<boolean> {
    return this.menuDishService.moveDishInMenu(menuId, dishId, direction);
  }

  async reorderDishes(menuId: string, dishIds: string[]): Promise<boolean> {
    return this.menuDishService.reorderDishes(menuId, dishIds);
  }

  async initializeOrderIndexes(menuId: string): Promise<boolean> {
    return this.menuDishService.initializeOrderIndexes(menuId);
  }

  // ========== METODI DI UTILITÀ ==========
  getCurrentMenus(): Menu[] {
    return this.menuService.data;
  }

  getCurrentMenuDishes(): MenuDish[] {
    return this.menuDishService.data;
  }

  isDishInMenu(menuId: string, dishId: string): boolean {
    return this.menuDishService.data.some(
      md => md.menu_id === menuId && md.dish_id === dishId && md.is_active
    );
  }

  getNextDisplayOrder(menuId: string): number {
    const dishes = this.menuDishService.data.filter(md => md.menu_id === menuId);
    return dishes.length ? Math.max(...dishes.map(d => d.display_order)) + 1 : 0;
  }

  async refreshAll(): Promise<void> {
    await Promise.all([this.loadMenus(), this.loadMenuDishes()]);
  }

  // 🔥 Manteniamo anche i vecchi alias per compatibilità (opzionale)
  async loadData(): Promise<void> {
    return this.loadMenus();
  }

  get data$(): Observable<Menu[]> {
    return this.menus$;
  }

  async delete(id: string): Promise<boolean> {
    return this.deleteMenu(id);
  }

  /**
 * Aggiorna un piatto nel menu (menu_dish)
 * Mantenuto per compatibilità con il vecchio codice
 */
async updateMenuDish(id: string, updates: Partial<MenuDish>): Promise<boolean> {
  return this.menuDishService.update(id, updates);
}



}